final:
module binary_counter (
  input clk,
  input rst,
  output reg [3:0] count,
  output reg max_reached
);

    wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt) begin
    if (rst) begin
      count <= 4'b0;
      max_reached <= 1'b0;
    end
    else if (count == 4'b1111) begin
      count <= 4'b0;
      max_reached <= 1'b1;
    end
    else begin
      count <= count + 1;
      max_reached <= 1'b0;
    end
  end

endmodule
